var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。`,ENG:`that you'll be with him, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called him to your office. He said he'd be here soon.`,TWN:`做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`BENEDICT_VATICAN_NULL_NULL`,text:{KOREA:`종신계약이라......`,JPN:`終身契約か……`,ENG:`A lifetime contract...`,TWN:`您說終身契約……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`BENEDICT_VATICAN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`BENEDICT_VATICAN_NULL_NULL`,text:{KOREA:`하긴, 선을 그을 줄 아는 자라면 진즉 날 심의회에 넘겼겠지.`,JPN:`ずいぶんと不躾だな。しかし、そもそも行儀の良い人間なら、とっくに私を審議会に引き渡していたことだろう。`,ENG:`Well, if you were not so generous, you would have turned me over to the Council a long time ago.`,TWN:`也是，你如果是個懂得劃清界線的人，早該把我交給審議會了。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`BENEDICT_VATICAN_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`BENEDICT_VATICAN_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`BENEDICT_VATICAN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`BENEDICT_VATICAN_NULL_NULL`,text:{KOREA:`세계를 휩쓸 시련을 막기 위해...... 오직 그 역할을 위해 이 손에 수많은 피를 묻혔지.`,JPN:`世界を巻き込む試練を阻止せんがため……ただその役目を担うためだけに、この手を何人もの血で染めてきた。`,ENG:`I don't know how much blood I've shed to protect this world against impending doom.`,TWN:`為了阻止世界即將迎來的試煉……就只為了這件事，我的手早已沾滿了鮮血。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`BENEDICT_VATICAN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`BENEDICT_VATICAN_NULL_NULL`,text:{KOREA:`그리고 이곳에 와서 깨달았다.`,JPN:`そして、ここに来て気付いたのだ。`,ENG:`When I came here, I've realized that...`,TWN:`然後，來到這裡後我發現了一件事。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`BENEDICT_VATICAN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`BENEDICT_VATICAN_NULL_NULL`,text:{KOREA:`방법은 달라도, 너 또한 나와 같이 이 세계를 위해 인고하고 있다는 사실을.`,JPN:`方法は違えど、君もまた私と同様に、この世界のために苦しみに耐えているということを。`,ENG:`you're sacrificing yourself for the good of this world just like I have, but in a different way.`,TWN:`雖然方法不同，但你也和我一樣，都在為了這個世界忍受痛苦。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`BENEDICT_VATICAN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`BENEDICT_VATICAN_NULL_NULL`,text:{KOREA:`그리고 나는......`,JPN:`そして、私は……`,ENG:`I'm...`,TWN:`而且……`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`BENEDICT_VATICAN_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`BENEDICT_VATICAN_NULL_NULL`,text:{KOREA:`아직 그런 모습을 외면할 수 있을 만큼 수양이 깊진 않군.`,JPN:`まだ、そのような姿を見過ごせるほど、達観してはいないのでな。`,ENG:`I'm not hardened enough to ignore someone like you, just yet.`,TWN:`我的修養還沒有好到能夠忽視你。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`BENEDICT_VATICAN_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};